        for(z2 = nach+2; z2 < mass.size(); z2++) {
            if(mass[z2] == '.') {
                flag2 = true;
                mass[nach] = '1';
                break;
            }
        }
    }
    bool boolik = false;
    if(flag1 && flag2) {
        boolik = otvet(mass, z1) || otvet(mass, z2);
    }
    else if(flag1) {
        boolik = otvet(mass, z1);
    }
    else if(flag2) {
        boolik = otvet(mass, z2);
    }
