One optimized algorithm for this problem is to use dynamic programming:

- Define DP[i] as the boolean value for whether the character can reach cell i or not.

- For each i, check if there is an obstacle at cell j and if DP[j] is true. If so, set DP[i] to true.

- Return DP[N-1].

Here's the C++ code implementing this algorithm:

```
#include <bits/stdc++.h>
using namespace std;

string s;

bool canReach(int n) {
    vector<bool> dp(n, false);
    dp[0] = true;

    for (int i = 0; i < n; i++) {
        if (s[i] == '.' || s[i] == 'X') {
            for (int j = i + 1; j < n && j <= i + 3; j++) {
                if (s[j] != '#' && s[j] != '?' && dp[i]) {
                    dp[j] = true;
                }
            }
        }
    }
    return dp[n - 1];
}

int main() {
    ios::sync_with_stdio(0);
    cin.tie(0); cout.tie(0);

    int n;
    cin >> n >> s;

    bool possible = canReach(n);
    if (possible) {
        cout << "YES\n";
    }
    else {
        cout << "NO\n";
    }

    return 0;
}
```

This code has a time complexity of O(n) and is therefore more optimal compared to the previous version, which had a time complexity of O(n^2).

